// Fecha Lima en formato YYYY-MM-DD (lo que espera PostgreSQL DATE)
const todayLima = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Lima' });

// INSERT atómico — si ya existe la fecha (PRIMARY KEY), Supabase devuelve 409
// Esto resuelve la condición de carrera: múltiples triggers simultáneos
// llegan a la BD al mismo tiempo, solo el primero en hacer INSERT gana.
// Los demás reciben 409 y se detienen silenciosamente.
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: SUP_URL + '/rest/v1/remaju_dispatch_lock',
    headers: {
      apikey: SUP_KEY,
      Authorization: 'Bearer ' + SUP_KEY,
      'Content-Type': 'application/json',
      Prefer: 'return=minimal'
    },
    body: JSON.stringify({ lock_date: todayLima }),
    timeout: 8000
  });
  // INSERT exitoso → primer dispatch del día → continuar
  return [{ json: { mode: 'dispatch', date: todayLima } }];
} catch(e) {
  const msg = String(e.message || '');
  // 409 = clave duplicada → ya corrió hoy → detener sin error
  if (msg.includes('409') || msg.includes('duplicate') || msg.includes('unique')) {
    return [];
  }
  // Tabla no existe aún u otro error → fail open (dejar pasar el dispatch)
  // Esto evita que un error de setup bloquee las alertas a usuarios reales
  return [{ json: { mode: 'dispatch', date: todayLima, lockWarning: msg.substring(0, 120) } }];
}
